                EnterZoomMode((_isFitMode ? GetFitScale() : _zoomLevel) * 1.25);
                break;

            case Key.OemMinus:
            case Key.Subtract:
                EnterZoomMode((_isFitMode ? GetFitScale() : _zoomLevel) / 1.25);
                break;

            case Key.Left:
            case Key.Up:
                if (_currentIndex > 0) { _currentIndex--; _ = LoadCurrentAsync(); }
                break;

            case Key.Right:
            case Key.Down:
            case Key.Return:
                if (_currentIndex < _rows.Count - 1) { _currentIndex++; _ = LoadCurrentAsync(); }
