                // Update the Findings column with the quick integrity result.
                // FindingsViewModel will overwrite this with full results when the item is selected.
                if (string.IsNullOrEmpty(row.FindingsText) || row.FindingsText == "0")
                    row.FindingsText = issues > 0 ? $"{issues} \u26a0" : "\u2713";
