public MainWindow(ShellViewModel viewModel)
    {
        InitializeComponent();
        DataContext = viewModel;

        // Restore keyboard focus to the grid after each folder load so the user
        // can immediately use cursor keys and Enter to navigate without clicking.
        // BeginInvoke at ContextIdle defers until after the current dispatcher
        // frame — including any OS focus-restoration that fires when a Win32
        // dialog (folder picker) hands focus back to the last-clicked button.
        viewModel.FolderLoaded += (_, _) =>
        {
            if (MediaGrid.Items.Count > 0 && MediaGrid.SelectedItem is null)
                MediaGrid.SelectedIndex = 0;

            Dispatcher.BeginInvoke(
                () => MediaGrid.Focus(),
                System.Windows.Threading.DispatcherPriority.ContextIdle);
        };
    }

